class Solution(object):
    def asteroidCollision(self, asteroids):
        stack = []
        for a in asteroids:
            alive = True
            while alive and a < 0 and stack and stack[-1] > 0:
                right = stack.pop()
                if right + a == 0:
                    alive = False
                elif right + a > 0:
                    stack.append(right)
                    alive = False
            if alive:
                stack.append(a)
        return stack
